import{c as n,S as h,j as i,m as c}from"./chunks/framework.8aa1YH_s.js";const e=JSON.parse('{"title":"Tiêu chí đề thi","description":"","frontmatter":{},"headers":[],"relativePath":"admin/tieu-chi-de-thi.md","filePath":"admin/tieu-chi-de-thi.md","lastUpdated":0}'),a={name:"admin/tieu-chi-de-thi.md"};function o(u,t,g,r,d,l){return h(),i("div",null,[...t[0]||(t[0]=[c('<h1 id="tieu-chi-đe-thi" tabindex="-1">Tiêu chí đề thi <a class="header-anchor" href="#tieu-chi-đe-thi" aria-label="Permalink to “Tiêu chí đề thi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/question/criteria</code></p><p>Tiêu chí đề thi là <strong>bộ quy tắc dựng đề tự động</strong>: hệ thống căn cứ vào tiêu chí để rút ngẫu nhiên câu hỏi từ <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a> sao cho đề mới luôn đảm bảo đúng cấu trúc (số câu, mức độ, chương/chuyên đề, dạng câu hỏi…).</p><h2 id="khi-nao-dung" tabindex="-1">Khi nào dùng <a class="header-anchor" href="#khi-nao-dung" aria-label="Permalink to “Khi nào dùng”">​</a></h2><ul><li>Khi cần <strong>sinh nhiều mã đề khác nhau</strong> từ cùng một cấu trúc (vd: tạo 20 mã đề ôn cho 20 lớp khác nhau).</li><li>Khi muốn <strong>chuẩn hóa cấu trúc đề</strong> trong một khóa học (mọi đề ôn đều đúng 50 câu trong đó 20 nhận biết, 20 thông hiểu, 10 vận dụng).</li><li>Khi dùng cho <a href="./de-on-khoa-hoc">Đề ôn khóa học</a>, <a href="./de-mau-luyen-thi">Đề mẫu Luyện thi</a>, <a href="./danh-gia-dau-vao">Đánh giá đầu vào</a> cần lấy câu hỏi tự động.</li></ul><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Tiêu chí đề thi <strong>không phải là đề thi</strong>. Nó chỉ là <strong>khuôn</strong>. Mỗi lần hệ thống dựng đề từ tiêu chí, các câu hỏi cụ thể có thể khác nhau (random theo điều kiện).</p></div><h2 id="danh-sach-tieu-chi" tabindex="-1">Danh sách tiêu chí <a class="header-anchor" href="#danh-sach-tieu-chi" aria-label="Permalink to “Danh sách tiêu chí”">​</a></h2><p>Các cột chính:</p><table tabindex="0"><thead><tr><th>Cột</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td>Tên tiêu chí</td><td>Tên gợi nhớ, vd &quot;Tiêu chí đề ôn Toán 12 - 50 câu&quot;</td></tr><tr><td>Khung chương trình</td><td>Khung chương trình áp dụng</td></tr><tr><td>Môn / Chuyên đề</td><td>Phạm vi nội dung</td></tr><tr><td>Tổng số câu</td><td>Tổng câu mà tiêu chí yêu cầu</td></tr><tr><td>Thời gian</td><td>Thời lượng làm bài (phút)</td></tr><tr><td>Người tạo</td><td>Tài khoản đã tạo tiêu chí</td></tr><tr><td>Trạng thái</td><td>Đang dùng / Ngưng</td></tr></tbody></table><h3 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h3><ul><li>Theo <strong>Khung chương trình</strong>.</li><li>Theo <strong>Môn</strong>.</li><li>Theo <strong>Người tạo</strong>.</li><li>Theo <strong>Trạng thái</strong>.</li><li>Tìm kiếm theo <strong>Tên tiêu chí</strong>.</li></ul><h2 id="tao-moi-tieu-chi" tabindex="-1">Tạo mới tiêu chí <a class="header-anchor" href="#tao-moi-tieu-chi" aria-label="Permalink to “Tạo mới tiêu chí”">​</a></h2><ol><li><p>Bấm <strong>Thêm mới</strong>.</p></li><li><p>Khai báo thông tin cơ bản:</p><ul><li><strong>Tên tiêu chí</strong> (bắt buộc, dùng nội bộ).</li><li><strong>Mô tả</strong> (tùy chọn).</li><li><strong>Khung chương trình</strong> áp dụng.</li><li><strong>Môn</strong> hoặc <strong>nhóm chuyên đề</strong>.</li><li><strong>Tổng số câu hỏi</strong> dự kiến.</li><li><strong>Thời gian làm bài</strong> (phút).</li></ul></li><li><p>Thêm các <strong>dòng cấu hình</strong> (mỗi dòng = 1 nhóm câu sẽ rút):</p><table tabindex="0"><thead><tr><th>Trường</th><th>Mô tả</th></tr></thead><tbody><tr><td>Chương / Chuyên đề</td><td>Lấy câu thuộc chương/chuyên đề nào</td></tr><tr><td>Mức độ</td><td>Nhận biết / Thông hiểu / Vận dụng / Vận dụng cao</td></tr><tr><td>Dạng câu hỏi</td><td>Trắc nghiệm 1 đáp án / Nhiều đáp án / Đúng-Sai / Điền số / Tự luận</td></tr><tr><td>Số câu</td><td>Số câu rút ngẫu nhiên từ điều kiện trên</td></tr><tr><td>Điểm/câu</td><td>Điểm trên mỗi câu (mặc định = tổng điểm / tổng câu)</td></tr></tbody></table></li><li><p>Tổng số câu trên các dòng phải <strong>bằng</strong> &quot;Tổng số câu hỏi&quot; đã khai ở bước 2.</p></li><li><p>Bấm <strong>Lưu</strong>.</p></li></ol><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Nếu số câu trong <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a> thỏa điều kiện ít hơn số câu yêu cầu, khi dựng đề sẽ báo lỗi &quot;Không đủ câu hỏi&quot;. Hãy bổ sung câu hỏi hoặc giảm số câu trong tiêu chí.</p></div><h2 id="vi-du-tieu-chi" tabindex="-1">Ví dụ tiêu chí <a class="header-anchor" href="#vi-du-tieu-chi" aria-label="Permalink to “Ví dụ tiêu chí”">​</a></h2><p><strong>Tiêu chí: Đề ôn cuối chương Hàm số - Toán 12 (40 câu, 60 phút)</strong></p><table tabindex="0"><thead><tr><th>Chuyên đề</th><th>Mức độ</th><th>Dạng</th><th>Số câu</th><th>Điểm/câu</th></tr></thead><tbody><tr><td>Hàm số bậc nhất</td><td>Nhận biết</td><td>Trắc nghiệm 1 đáp án</td><td>5</td><td>0.2</td></tr><tr><td>Hàm số bậc nhất</td><td>Thông hiểu</td><td>Trắc nghiệm 1 đáp án</td><td>5</td><td>0.25</td></tr><tr><td>Hàm số bậc hai</td><td>Nhận biết</td><td>Trắc nghiệm 1 đáp án</td><td>5</td><td>0.2</td></tr><tr><td>Hàm số bậc hai</td><td>Thông hiểu</td><td>Trắc nghiệm 1 đáp án</td><td>5</td><td>0.25</td></tr><tr><td>Hàm số bậc hai</td><td>Vận dụng</td><td>Trắc nghiệm nhiều đáp án</td><td>10</td><td>0.3</td></tr><tr><td>Hàm số bậc hai</td><td>Vận dụng cao</td><td>Điền số</td><td>10</td><td>0.35</td></tr></tbody></table><p>→ Tổng 40 câu, tổng điểm 10.</p><h2 id="sua-tieu-chi" tabindex="-1">Sửa tiêu chí <a class="header-anchor" href="#sua-tieu-chi" aria-label="Permalink to “Sửa tiêu chí”">​</a></h2><ol><li>Tại danh sách, bấm biểu tượng <strong>Sửa</strong> (cây bút) trên dòng tương ứng.</li><li>Cập nhật các trường cần đổi.</li><li>Bấm <strong>Lưu</strong>.</li></ol><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Sửa tiêu chí <strong>không ảnh hưởng</strong> đến các đề đã được sinh ra trước đó. Chỉ các lần dựng đề <strong>sau khi sửa</strong> mới dùng cấu hình mới.</p></div><h2 id="xoa-tieu-chi" tabindex="-1">Xóa tiêu chí <a class="header-anchor" href="#xoa-tieu-chi" aria-label="Permalink to “Xóa tiêu chí”">​</a></h2><ol><li>Bấm biểu tượng <strong>Xóa</strong> (thùng rác) trên dòng cần xóa.</li><li>Xác nhận trong hộp thoại.</li></ol><div class="danger custom-block"><p class="custom-block-title custom-block-title-default">DANGER</p><p>Không thể xóa tiêu chí đang được <strong>gắn vào đề thi / khóa học đang công khai</strong>. Hãy gỡ liên kết hoặc đặt tiêu chí về trạng thái <strong>Ngưng</strong> thay vì xóa.</p></div><h2 id="sao-chep-nhan-ban-tieu-chi" tabindex="-1">Sao chép (Nhân bản) tiêu chí <a class="header-anchor" href="#sao-chep-nhan-ban-tieu-chi" aria-label="Permalink to “Sao chép (Nhân bản) tiêu chí”">​</a></h2><p>Khi cần tạo tiêu chí mới gần giống tiêu chí cũ:</p><ol><li>Tại dòng tiêu chí gốc, bấm biểu tượng <strong>Nhân bản</strong> (copy).</li><li>Hệ thống tạo bản sao với hậu tố &quot;(Bản sao)&quot;.</li><li>Mở ra, đổi tên và chỉnh các dòng cấu hình theo nhu cầu.</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="su-dung-tieu-chi-trong-đe-thi" tabindex="-1">Sử dụng tiêu chí trong đề thi <a class="header-anchor" href="#su-dung-tieu-chi-trong-đe-thi" aria-label="Permalink to “Sử dụng tiêu chí trong đề thi”">​</a></h2><p>Khi tạo <a href="./de-on-khoa-hoc">Đề ôn khóa học</a> hoặc đề kiểm tra cuối chuyên đề, có 2 chế độ:</p><ul><li><strong>Cố định</strong>: chọn sẵn từng câu hỏi → mỗi học viên nhận đề giống nhau.</li><li><strong>Theo tiêu chí</strong>: chọn 1 tiêu chí → mỗi học viên (hoặc mỗi mã đề) sẽ được rút câu khác nhau.</li></ul><p>→ Chế độ &quot;Theo tiêu chí&quot; rất phù hợp khi muốn <strong>chống gian lận</strong>: hai học viên ngồi cạnh nhau sẽ thấy đề khác nhau dù cùng cấu trúc.</p><h2 id="xuat-nhap-tieu-chi" tabindex="-1">Xuất / Nhập tiêu chí <a class="header-anchor" href="#xuat-nhap-tieu-chi" aria-label="Permalink to “Xuất / Nhập tiêu chí”">​</a></h2><ul><li><strong>Xuất Excel</strong>: bấm <strong>Xuất Excel</strong> để tải danh sách tiêu chí kèm cấu hình. Hữu ích khi backup hoặc chia sẻ cấu trúc đề với đồng nghiệp.</li><li>Nhập từ Excel: hiện chỉ hỗ trợ tạo thủ công từng tiêu chí; nếu cần nhập hàng loạt, liên hệ quản trị hệ thống.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi đã tạo tiêu chí nhưng khi dựng đề báo &quot;Không đủ câu hỏi&quot; - phải làm gì?</strong> → Kiểm tra trong <a href="./danh-muc-cau-hoi">Danh mục câu hỏi</a>: lọc theo cùng chuyên đề, mức độ, dạng câu xem có bao nhiêu câu khả dụng. Nếu thiếu, bổ sung câu mới hoặc giảm số câu yêu cầu trong tiêu chí.</p><p><strong>Có thể đặt 1 câu hỏi xuất hiện ở nhiều dòng tiêu chí khác nhau không?</strong> → Không. Trong một lần dựng đề, mỗi câu chỉ rút <strong>tối đa 1 lần</strong>. Nếu dòng tiêu chí khác nhau cùng nhắm tới nhóm câu giống nhau, có thể bị xung đột.</p><p><strong>Tôi muốn 100% học viên nhận đúng 1 đề giống nhau, không random - có dùng tiêu chí được không?</strong> → Không cần dùng tiêu chí. Hãy tạo đề thi ở chế độ <strong>Cố định</strong> và chọn tay từng câu.</p><p><strong>Tôi muốn cứ mỗi lần học viên làm lại thì đề lại khác?</strong> → Khi cấu hình đề thi, bật <strong>Random lại đề mỗi lần làm</strong>. Hệ thống sẽ chạy lại tiêu chí cho mỗi lượt làm.</p><p><strong>Khác nhau giữa &quot;Tiêu chí đề thi&quot; và &quot;Bộ đề thi&quot;?</strong> → Tiêu chí = <strong>khuôn dựng đề</strong> (chỉ định cấu trúc). <a href="./bo-de-thi">Bộ đề thi</a> = <strong>tập hợp các đề thi cụ thể đã có sẵn nội dung</strong>, dùng để gán hàng loạt cho lớp/khóa.</p><p><strong>Tôi sửa tiêu chí, các đề đã giao trước đó có bị đổi không?</strong> → Không. Đề đã giao giữ nguyên các câu đã rút. Chỉ ảnh hưởng lần dựng đề tiếp theo.</p>',40)])])}const m=n(a,[["render",o]]);export{e as __pageData,m as default};
